const featureDescription = $('Set Variables').first().json.featureDescription || '';
const additionalContext = $('Set Variables').first().json.additionalContext || '';
const template = $('Set Variables').first().json.template || 'generic';

const ROLES = {
  'generic': 'You are a senior software architect performing technical analysis.',
  'new-feature': 'You are a senior software architect designing a new feature.',
  'tech-migration': 'You are a senior architect planning a technology migration. Must be incremental and reversible.',
  'large-refactoring': 'You are a senior architect planning a major refactoring. Must preserve existing behavior.',
  'api-breaking-change': 'You are a senior API architect planning a breaking change. Minimize consumer disruption.',
  'security-audit': 'You are a senior security engineer documenting audit findings with severity scores and fixes.',
  'performance-optimization': 'You are a senior performance engineer with measurable improvement targets.',
  'scheduled-task-migration': 'You are a senior architect migrating a legacy scheduled task to a modern job framework. Produce a Discovery Document and Migration Plan.',
  'adr': 'You are a senior architect documenting an Architecture Decision Record.',
  'post-mortem': 'You are a senior SRE writing a blameless post-mortem.',
  'runbook': 'You are a senior SRE writing a runbook. Every command must be copy-pasteable.',
  'service-documentation': 'You are a senior software engineer writing internal documentation for a service, application, or library. Your audience is developers new to this codebase who need to get up to speed quickly. Be specific and practical.',
  'bug-fix': 'You are a senior developer triaging a bug with root cause analysis.',
  'dependency-update': 'You are a senior developer planning a dependency upgrade.',
  'tech-debt': 'You are a senior developer documenting tech debt with business justification.',
  'quick-enhancement': 'You are a senior developer scoping a small enhancement (< 1 day).'
};

const SCHEMAS = {
  'scheduled-task-migration': 'Produce JSON with: title, summary, discoveryDocument (purpose with what/why/when, codeLocation with workerClass/baseClass/entryPoint/projectFile/supportingFiles each with path, howItWorks with entryFlow and coreAlgorithm steps each with codeSample and sourceFile and lineRange, dataAccess with databases and externalServices, errorHandling with strategy and codeSample, inputsAndOutputs with inputs/outputs/sideEffects, configuration, knownIssues, runInstructions with prerequisites/buildSteps/runSteps/debugSteps/testSteps), migrationPlan (targetDesign with projectName/className/jobId/interface/targetPath/namespace, dependencyMapping with mappings each having legacy/legacyFile/target/action, phases each with name/goal/prerequisite/canRollback/rollbackSteps/attentionPoints/tasks/validationChecks, improvements with codeQuality/linting/testing/performance/observability, cleanupPhase with filesToRemove and configToRemove, risks, openQuestions), estimatedComplexity, suggestedApproach. Every code reference MUST include file path.',
  'adr': 'Produce JSON with: title, status (Proposed), date, context (background, constraints, drivers, assumptions), options (each with name, description, pros, cons, effort, risk, operationalImpact, teamFamiliarity), decision (chosen, reasoning, dissent), consequences (positive, negative, neutral), followUp (actions, reviewDate, reversibility).',
  'post-mortem': 'Produce JSON with: title, severity (SEV1-4), duration, status, summary, impact (usersAffected, revenueImpact, dataLoss, slaBreached), timeline (timestamp, event, actor), rootCause (primary, contributing, fiveWhys), detection (howDetected, timeToDetect, alertsFired, alertsExpectedButMissing), response (timeToMitigate, mitigationSteps, whatWorkedWell, whatCouldBeImproved), actionItems (description, type: prevent|detect|mitigate, priority, owner, deadline), lessonsLearned.',
  'runbook': 'Produce JSON with: title, service, overview (purpose, criticality, dependencies, dependents), healthChecks (name, command, healthyOutput, unhealthyOutput), commonIssues (symptom, cause, diagnosis steps, resolution steps, escalation), procedures (name, when, steps with instruction/expectedResult/ifFailed, rollback), contacts, links.',
  'service-documentation': 'Produce JSON with: title, summary, overview (purpose, type: service|application|library|cli-tool|worker|scheduled-job, techStack, repository, owners), keyFiles (path, purpose, notes), architecture (overview, entryPoint, keyModules with name/path/responsibility/publicInterface, dataFlow), howToRun (prerequisites, setup steps, run with development/production/docker commands, environment with variable/description/required/default, verification), directoryStructure (description, tree with path/description), potentialIssues (issue, severity: low|medium|high, context, workaround), improvements (title, description, effort: XS|S|M|L|XL, impact: low|medium|high, category: code-quality|performance|reliability|developer-experience|security|testing), dependencies (runtime, external, consumers), testing (howToTest, testStructure, coverage).',
  'bug-fix': 'Produce JSON with: title, severity, description, reproductionSteps, expectedBehavior, actualBehavior, rootCause (hypothesis, confidence, investigation), fixApproach (description, affectedFiles, riskLevel), tasks as subtasks with acceptanceCriteria, testPlan (unitTests, manualVerification), workaround.',
  'dependency-update': 'Produce JSON with: title, packages (name, currentVersion, targetVersion, changelog, breakingChanges with description/affectedCode/migration, newFeatures, deprecations), riskAssessment (overall, peerDependencies, knownIssues), tasks as subtasks, verificationPlan, rollbackPlan.',
  'tech-debt': 'Produce JSON with: title, currentState (description, pain, frequency), desiredState (description, benefit), justification (developerProductivity, reliability, riskReduction, onboarding), approach (description, canBeIncremental, estimatedEffort, bestTimeToFix), acceptanceCriteria, risks.',
  'quick-enhancement': 'Produce JSON with: title, description, scope (includes, excludes, isActuallyBigger, biggerNote), implementation (approach, affectedFiles, estimate max M), acceptanceCriteria (max 5), testPlan.',
  'api-breaking-change': 'Produce JSON with: title, summary, currentContract (endpoints, consumers with impactLevel), proposedContract (endpoints with changeType, versioningStrategy), diff (field, before, after, breakingReason, migrationAction), migrationPlan (strategy, phases, deprecationTimeline, migrationGuide with steps and codeExamples), communication (announcement, channels, faq), tasks, testing (contractTests, migrationTests, compatibilityTests), rollbackPlan, risks.',
  'security-audit': 'Produce JSON with: title, auditScope (areasReviewed, areasOutOfScope, methodology), overallRisk, findingsCount by severity, findings (id like SEC-001, title, severity, category, owaspCategory, description, affectedComponent, reproductionSteps, impact, exploitability, evidence, remediation with recommendation/codeExample/effort/priority), positiveFindings, recommendations (immediate, shortTerm, longTerm), tasks, complianceNotes, retestDate.',
  'performance-optimization': 'Produce JSON with: title, currentState (metrics with name/currentValue/target/gap, userImpact, businessImpact), analysis (bottlenecks with location/type/description/evidence/contribution%, hotPaths, redHerrings), optimizations (id like OPT-001, title, description, type, targetBottleneck, expectedImprovement, confidence, effort, risk, tradeoff), quickWins, benchmarkPlan (tooling, baselineTests, regressionTests, loadProfile), tasks, monitoringPlan (dashboards, alerts, continuousBaseline), antiPatterns.',
  'tech-migration': 'Produce JSON with: title, currentState (technology, version, usage, knownIssues), targetState (technology, version, benefits, tradeoffs), impactAnalysis (affectedServices with impactLevel, affectedTeams, breakingChanges, dataChanges), migrationStrategy (approach: strangler-fig|parallel-run|feature-flag, reasoning, parallelRunPeriod, featureFlags), phases (name, goal, prerequisite, canRollback, rollbackSteps, tasks, validationChecks), rollbackPlan (fullRollbackSteps, pointOfNoReturn, dataRollback), testing (parallelRunTests, regressionTests, newTests, performanceBenchmarks), risks with contingency, timeline.'
};

const DEFAULT_SCHEMA = 'Produce JSON with: title, summary, architecture (overview, components with name/type/description/changes, dataFlow), apiContracts (method, path, description, requestBody, responseBody, statusCodes), databaseChanges (type, entity, description, fields with name/type/nullable), edgeCases (scenario, impact, mitigation), securityConsiderations, testingStrategy (unitTests, integrationTests, e2eTests), tasks (type: epic|story|subtask, summary, description, component, estimate: XS|S|M|L|XL, priority, acceptanceCriteria in Given/When/Then), estimatedComplexity, suggestedApproach.';

const customRole = $('Set Variables').first().json.customRole || '';
const customSchema = $('Set Variables').first().json.customSchema || '';
const role = customRole || ROLES[template] || ROLES['generic'];
const schema = customSchema || SCHEMAS[template] || DEFAULT_SCHEMA;

const prompt = role + '\n\nAnalyze the following and produce a detailed JSON response.\n\n## Description\n' + featureDescription + '\n\n## Additional Context\n' + additionalContext + '\n\n## Output\n\nRespond ONLY with valid JSON. No markdown code fences, no explanation — just the JSON object.\n\n' + schema + '\n\nAlso include: title, summary, estimatedComplexity (low|medium|high), suggestedApproach.\nRules: Tasks 1-3 day items. Gherkin acceptance criteria. Be specific. XS(<2h) S(2-4h) M(4-8h) L(1-2d) XL(2-3d).';

const model = $env.AI_MODEL || 'openai/gpt-4.1';
const maxTokens = parseInt($env.AI_MAX_TOKENS || '4096', 10);
const authHeader = 'Bearer ' + ($env.GITHUB_TOKEN || '');

return [{ json: { requestBody: { model, max_tokens: maxTokens, messages: [{ role: 'user', content: prompt }] }, authHeader, featureDescription, additionalContext, template, systemRole: role, schema } }];

const response = $input.first().json;
const content = response.choices[0].message.content;

let jsonStr = content;
if (content.includes('```json')) jsonStr = content.split('```json')[1].split('```')[0].trim();
else if (content.includes('```')) jsonStr = content.split('```')[1].split('```')[0].trim();

let analysis;
try { analysis = JSON.parse(jsonStr); }
catch (e) { throw new Error('Failed to parse initial AI response: ' + e.message + '\n\nRaw: ' + content.substring(0, 500)); }

// Pass through context from Build Generate Request
const gen = $('Build Generate Request').first().json;
return [{ json: { analysis, featureDescription: gen.featureDescription, additionalContext: gen.additionalContext, systemRole: gen.systemRole, schema: gen.schema, authHeader: gen.authHeader } }];

const prev = $input.first().json;
const model = $env.AI_MODEL || 'openai/gpt-4.1';
const maxTokens = parseInt($env.AI_MAX_TOKENS || '4096', 10);

const critiquePrompt = 'You previously produced this technical analysis:

' + JSON.stringify(prev.analysis, null, 2) + '

Critically review your own output. Identify:
1. Missing edge cases or security concerns
2. Overly vague or generic sections that need concrete details
3. Unrealistic estimates or missing tasks
4. Inconsistencies between sections
5. Anything a senior tech lead would push back on

Respond ONLY with valid JSON:
{
  "strengths": ["what is good about this analysis"],
  "weaknesses": ["what is missing, vague, or wrong"],
  "suggestions": ["specific improvements to make"]
}';

return [{ json: { requestBody: { model, max_tokens: maxTokens, messages: [{ role: 'system', content: prev.systemRole }, { role: 'user', content: critiquePrompt }] }, authHeader: prev.authHeader, analysis: prev.analysis, featureDescription: prev.featureDescription, additionalContext: prev.additionalContext, systemRole: prev.systemRole, schema: prev.schema } }];

const response = $input.first().json;
const content = response.choices[0].message.content;

let jsonStr = content;
if (content.includes('```json')) jsonStr = content.split('```json')[1].split('```')[0].trim();
else if (content.includes('```')) jsonStr = content.split('```')[1].split('```')[0].trim();

let critique;
try { critique = JSON.parse(jsonStr); }
catch (e) { critique = { strengths: [], weaknesses: [content.substring(0, 500)], suggestions: ['Could not parse critique — using raw text as feedback'] }; }

const prev = $('Build Critique Request').first().json;
const model = $env.AI_MODEL || 'openai/gpt-4.1';
const maxTokens = parseInt($env.AI_MAX_TOKENS || '4096', 10);

const refinePrompt = 'Original feature description:
' + prev.featureDescription + '

Additional context:
' + prev.additionalContext + '

Your initial analysis:
' + JSON.stringify(prev.analysis, null, 2) + '

Self-critique findings:
' + JSON.stringify(critique, null, 2) + '

Now produce an IMPROVED version of the analysis that addresses all weaknesses and incorporates all suggestions. The improved version must be more specific, more detailed, and more actionable than the original.

' + prev.schema + '

Also include: title, summary, estimatedComplexity (low|medium|high), suggestedApproach.
Rules: Tasks 1-3 day items. Gherkin acceptance criteria. Be specific. XS(<2h) S(2-4h) M(4-8h) L(1-2d) XL(2-3d).

Respond ONLY with valid JSON. No markdown code fences, no explanation — just the JSON object.';

return [{ json: { requestBody: { model, max_tokens: maxTokens, messages: [{ role: 'system', content: prev.systemRole }, { role: 'user', content: refinePrompt }] }, authHeader: prev.authHeader, iteration: 1 } }];

const vars = $('Set Variables').first().json;
const template = vars.template || 'generic';
const previousAnalysis = vars.previousAnalysis ? JSON.parse(vars.previousAnalysis) : {};
const feedback = vars.feedback || '';
const iteration = (vars.iteration || 0) + 1;

const ROLES = {
  'generic': 'You are a senior software architect performing technical analysis.',
  'new-feature': 'You are a senior software architect designing a new feature.',
  'tech-migration': 'You are a senior architect planning a technology migration. Must be incremental and reversible.',
  'large-refactoring': 'You are a senior architect planning a major refactoring. Must preserve existing behavior.',
  'api-breaking-change': 'You are a senior API architect planning a breaking change. Minimize consumer disruption.',
  'security-audit': 'You are a senior security engineer documenting audit findings with severity scores and fixes.',
  'performance-optimization': 'You are a senior performance engineer with measurable improvement targets.',
  'scheduled-task-migration': 'You are a senior architect migrating a legacy scheduled task to a modern job framework.',
  'adr': 'You are a senior architect documenting an Architecture Decision Record.',
  'post-mortem': 'You are a senior SRE writing a blameless post-mortem.',
  'runbook': 'You are a senior SRE writing a runbook. Every command must be copy-pasteable.',
  'service-documentation': 'You are a senior software engineer writing internal documentation for a service, application, or library. Be specific and practical.',
  'bug-fix': 'You are a senior developer triaging a bug with root cause analysis.',
  'dependency-update': 'You are a senior developer planning a dependency upgrade.',
  'tech-debt': 'You are a senior developer documenting tech debt with business justification.',
  'quick-enhancement': 'You are a senior developer scoping a small enhancement (< 1 day).'
};

const SCHEMAS = {
  'scheduled-task-migration': 'Produce JSON with: title, summary, discoveryDocument (purpose with what/why/when, codeLocation, howItWorks, dataAccess, errorHandling, inputsAndOutputs, configuration, knownIssues, runInstructions), migrationPlan (targetDesign, dependencyMapping, phases, improvements, cleanupPhase, risks, openQuestions), estimatedComplexity, suggestedApproach.',
  'adr': 'Produce JSON with: title, status, date, context, options, decision, consequences, followUp.',
  'post-mortem': 'Produce JSON with: title, severity, duration, status, summary, impact, timeline, rootCause, detection, response, actionItems, lessonsLearned.',
  'runbook': 'Produce JSON with: title, service, overview, healthChecks, commonIssues, procedures, contacts, links.',
  'service-documentation': 'Produce JSON with: title, summary, overview, keyFiles, architecture, howToRun, directoryStructure, potentialIssues, improvements, dependencies, testing.',
  'bug-fix': 'Produce JSON with: title, severity, description, reproductionSteps, expectedBehavior, actualBehavior, rootCause, fixApproach, tasks, testPlan, workaround.',
  'dependency-update': 'Produce JSON with: title, packages, riskAssessment, tasks, verificationPlan, rollbackPlan.',
  'tech-debt': 'Produce JSON with: title, currentState, desiredState, justification, approach, acceptanceCriteria, risks.',
  'quick-enhancement': 'Produce JSON with: title, description, scope, implementation, acceptanceCriteria, testPlan.',
  'api-breaking-change': 'Produce JSON with: title, summary, currentContract, proposedContract, diff, migrationPlan, communication, tasks, testing, rollbackPlan, risks.',
  'security-audit': 'Produce JSON with: title, auditScope, overallRisk, findingsCount, findings, positiveFindings, recommendations, tasks, complianceNotes, retestDate.',
  'performance-optimization': 'Produce JSON with: title, currentState, analysis, optimizations, quickWins, benchmarkPlan, tasks, monitoringPlan, antiPatterns.',
  'tech-migration': 'Produce JSON with: title, currentState, targetState, impactAnalysis, migrationStrategy, phases, rollbackPlan, testing, risks, timeline.'
};

const DEFAULT_SCHEMA = 'Produce JSON with: title, summary, architecture, apiContracts, databaseChanges, edgeCases, securityConsiderations, testingStrategy, tasks, estimatedComplexity, suggestedApproach.';

const customRole = vars.customRole || '';
const customSchema = vars.customSchema || '';
const role = customRole || ROLES[template] || ROLES['generic'];
const schema = customSchema || SCHEMAS[template] || DEFAULT_SCHEMA;

const refinePrompt = 'Here is the current technical analysis:\n\n' + JSON.stringify(previousAnalysis, null, 2) + '\n\nThe reviewer provided this feedback:\n\n' + feedback + '\n\nProduce an improved version of the analysis that addresses ALL of the reviewer feedback. Keep everything that was already good, and improve or add what was requested.\n\n' + schema + '\n\nAlso include: title, summary, estimatedComplexity (low|medium|high), suggestedApproach.\nRules: Tasks 1-3 day items. Gherkin acceptance criteria. Be specific. XS(<2h) S(2-4h) M(4-8h) L(1-2d) XL(2-3d).\n\nRespond ONLY with valid JSON. No markdown code fences, no explanation — just the JSON object.';

const model = $env.AI_MODEL || 'openai/gpt-4.1';
const maxTokens = parseInt($env.AI_MAX_TOKENS || '4096', 10);
const authHeader = 'Bearer ' + ($env.GITHUB_TOKEN || '');

return [{ json: { requestBody: { model, max_tokens: maxTokens, messages: [{ role: 'system', content: role }, { role: 'user', content: refinePrompt }] }, authHeader, iteration } }];

const response = $input.first().json;
const content = response.choices[0].message.content;

let jsonStr = content;
if (content.includes('```json')) jsonStr = content.split('```json')[1].split('```')[0].trim();
else if (content.includes('```')) jsonStr = content.split('```')[1].split('```')[0].trim();

let analysis;
try { analysis = JSON.parse(jsonStr); }
catch (e) { throw new Error('Failed to parse AI response: ' + e.message + '\n\nRaw: ' + content.substring(0, 500)); }

// Determine iteration: generate branch = 1 (from auto-refine), refine branch = incremented
const action = $('Set Variables').first().json.action;
let iteration;
if (action === 'refine') {
  iteration = ($('Set Variables').first().json.iteration || 0) + 1;
} else {
  iteration = 1;
}

return [{ json: { analysis, iteration, featureDescription: $('Set Variables').first().json.featureDescription } }];

const { analysis, iteration } = $input.first().json;
const date = new Date().toISOString().split('T')[0];
let md = '';

md += '# ' + (analysis.title || 'Analysis') + '\n\n';
md += '> Generated on ' + date + ' by [ai-confluence-pipeline](https://github.com/openmindednewby/ai-confluence-pipeline) — Iterative Preview (iteration ' + iteration + ')\n\n';
if (analysis.estimatedComplexity) md += '**Complexity:** ' + analysis.estimatedComplexity;
if (analysis.suggestedApproach) md += ' | **Approach:** ' + analysis.suggestedApproach;
md += '\n\n---\n\n';
if (analysis.summary) md += '## Summary\n\n' + analysis.summary + '\n\n';

function renderSection(obj, depth) {
  if (!obj || typeof obj !== 'object') return String(obj || '') + '\n';
  let out = '';
  if (Array.isArray(obj)) {
    if (obj.length > 0 && typeof obj[0] === 'object' && !Array.isArray(obj[0])) {
      const keys = Object.keys(obj[0]);
      if (keys.length <= 8 && keys.length >= 2 && obj.every(item => typeof item === 'object' && !Array.isArray(item))) {
        out += '| ' + keys.map(k => k.replace(/([A-Z])/g, ' $1').trim()).join(' | ') + ' |\n';
        out += '| ' + keys.map(() => '---').join(' | ') + ' |\n';
        for (const item of obj) {
          out += '| ' + keys.map(k => {
            const v = item[k];
            if (Array.isArray(v)) return v.join(', ');
            if (typeof v === 'object' && v !== null) return JSON.stringify(v);
            return String(v ?? '');
          }).join(' | ') + ' |\n';
        }
        out += '\n';
        return out;
      }
    }
    for (const item of obj) {
      if (typeof item === 'string') out += '- ' + item + '\n';
      else if (typeof item === 'object') out += renderSection(item, depth);
    }
    out += '\n';
    return out;
  }
  const skip = ['title', 'summary', 'estimatedComplexity', 'suggestedApproach'];
  for (const [key, value] of Object.entries(obj)) {
    if (skip.includes(key) && depth === 0) continue;
    const heading = key.replace(/([A-Z])/g, ' $1').replace(/^./, s => s.toUpperCase()).trim();
    if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
      out += '**' + heading + ':** ' + value + '\n\n';
    } else if (Array.isArray(value) && value.length > 0 && typeof value[0] === 'string') {
      out += '**' + heading + ':**\n';
      for (const item of value) out += '- ' + item + '\n';
      out += '\n';
    } else if (value && typeof value === 'object') {
      const hPrefix = '#'.repeat(Math.min(depth + 2, 4));
      out += hPrefix + ' ' + heading + '\n\n';
      out += renderSection(value, depth + 1);
    }
  }
  return out;
}

md += renderSection(analysis, 0);

return [{ json: { success: true, title: analysis.title || 'Analysis', markdown: md, analysis, iteration } }];
